INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (0, 2834, "青空の下で謁見", 20063115, 10118, 8, 91002, 1, "フリーマーケット会場", 5118061, "ペコリーヌとの出会い", 7, "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 2, 40);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (0, 2835, "未来の騎空団\nマスコット？", 20063115, 10118, 8, 91002, 1, "フリーマーケット会場", 5118062, "マホとの出会い", 7, "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 2, 40);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (0, 2837, "お嬢さまからの\n緊急依頼", 20063115, 10118, 8, 91002, 1, "ランドソル市街地", 5118063, "アキノとの出会い", 7, "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 2, 40);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (0, 4108402, "黄金色の悩みごと", 20063115, 10118, 8, 91002, 1, "フリーマーケット会場", 5118064, "ジュンとの出会い", 18, "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 2, 40);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (0, 4107402, "白熱！　格闘大会！", 20063115, 10118, 8, 91002, 1, "フリーマーケット会場", 5118065, "カオリとの出会い", 18, "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 2, 40);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (1, 9000227, "祭り太鼓はオーエドの華", 20063115, 10118, 8, 91002, 1, "オーエド町", 5118066, "ニノンとの出会い", 16, "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 2, 40);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (0, 2101181, "人気者は遅れて\nやってくる", 20063115, 10118, 8, 91002, 1, "フリーマーケット会場", 5118067, "スズナとの出会い", 19, "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 3, 40);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (0, 4109402, "巫女・ミーツ・魔法少女", 20063115, 10118, 8, 91002, 1, "ランドソル市街地", 5118068, "ナナカとの出会い", 18, "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 3, 40);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (0, 4305402, "ネズ耳は二度なくなる", 20063115, 10118, 8, 91002, 1, "フリーマーケット会場", 5118069, "キャル＆コッコロとの出会い", 18, "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 3, 40);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (0, 4101402, "この出会いにカンパイ！", 20063115, 10118, 8, 91002, 1, "ランドソル市街地", 5118070, "ユカリとの出会い", 18, "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 3, 40);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (0, 4106402, "陰陽アンサンブル", 20063115, 10118, 8, 91002, 1, "ランドソル市街地", 5118071, "アオイとの出会い", 18, "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 3, 40);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (1, 2836, "運試し十番勝負！", 20063115, 10118, 8, 91002, 1, "フリーマーケット会場", 5118072, "シノブとの出会い", 7, "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 3, 40);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (0, 0, "彼女たちの新たな日常", 20063115, 10118, 0, 0, 0, 0, 5118600, "オープニング", 0, 0, 1, 0);
